function LSdkCpX3:Initialize()
    LSdkCpBase.Initialize(self)
    if LOG_INFO_ENABLED then
        printInfoN2("sdk", ">>> x3 sdk Initialize ...")
    end

    --self._currency = "RMB"
    --self._currencySymbol = "￥"
    self._currency = "TWD"
    self._currencySymbol = "NT$"
    --self._currency = "USD"
    --self._currencySymbol = "$"
    self:SetSupportPay(true)

    self._sPackageId = LGameSettings.platformId

    if LGameSettings.platformRegion == LRegionConst.AMERICA then
        self._currency = "USD"
        self._currencySymbol = "$"
    elseif LGameSettings.platformRegion == LRegionConst.SEA then
        self._currency = "USD"
        self._currencySymbol = "$"
    end
end

function LSdkCpX3:IsForbidNewSelServer()
    if LGameSettings.platformRegion == LRegionConst.JAPAN then
        return true
    end
    return false
end

