function LSdkCpX3:OnInternalCreateOrderOk(orderData)
    local payData = self._reqOrderData.payData
    local tgaData = self._reqOrderData.tgaData
    local msgStr = ""
    local strList = {}
    for k,v in pairs(payData) do
        local tempStr = string.format("%s -> %s, ",k,v)
        table.insert(strList,tempStr)
    end
    msgStr = table.concat(strList)
    GF.ShowAlert({title="PayTest",msg = msgStr,okFunc = function()
          gModelPay:DebugPay(payData)
    end, cancelFunc = function() end})
end

