function LSdkCpX3:GetABTestRes()
    -- 提审默认 1
    if PRODUCT_G_VER and PRODUCT_G_VER ~= 0 then
        local ref = self:GetSdkChnResourcesRef()
        self:SetSdkChnResourcesRef(ref)
        printInfoN("-----资源类型检测 " .. LPlayerPrefs.GetLocalization())
        return true, true
    end
    --- 国内改为全部都要检测
    return self:UpdateNormalABTest()
end

function LSdkCpX3:GetSdkPackId()

end

function LSdkCpX3:GetSdkChnResourcesRef()
    local sId = gModelGM:GetPackId() or tostring(self._sPackageId)
    local defaultRef
    local refs = GameTable.SdkChnResources
    for k,v in pairs(refs) do
        if v.name == sId then
            return v
        end
        if v.name == "101" then
            defaultRef = v
        end
    end
    ---  如果有包没有加的话，默认走101这个包的配置
    return defaultRef
end

function LSdkCpX3:CheckIsSpecificPuid()
    return false
end

function LSdkCpX3:IsBlacklist()
    return gModelGM:GetIsBlackType()
end

function LSdkCpX3:UpdateNormalABTest()
    local isCtrlABTestRes = true
    local isBRes = true
    local ref = self:GetSdkChnResourcesRef()
    local resources = ref.resources
    --- 0表示不走ab资源，1表示走ab资源
    if resources and resources == 0 then
        self:SetSdkChnResourcesRef(ref)
        return isCtrlABTestRes,isBRes
    end
    if self:IsBlacklist() then
        self:UpdateBlackListABTest()
    else
        --- 非黑名单
        if self:CheckIsSpecificPuid() then
            self._isBlacklist = true
            self:UpdateBlackListABTest()
        else
            --- 归因资源判断
            isCtrlABTestRes,isBRes = self:UpdateAfStatusABTest()
        end
    end
    return isCtrlABTestRes,isBRes
end

function LSdkCpX3:UpdateBlackListABTest()
    local ref = self:GetSdkChnResourcesRef()
    self:SetNoChangeLocalization(ref.blacklist)
end

function LSdkCpX3:SetNoChangeLocalization(resType)
    LPlayerPrefs.LimitResType(false)
    ---- 没有接入归因时走的字段
    LPlayerPrefs.GMSetLocalization(resType)
    LPlayerPrefs.LimitResType(true)
end

function LSdkCpX3:SetSdkChnResourcesRef(ref)
    local resType = LPlayerPrefs.GetLocalization()
    ---@type boolean 是否使用了正确的资源类型
    local isInOnly = false
    local parameterOnly = string.split(ref.parameterOnly,",")
    for i,v in ipairs(parameterOnly) do
        if checknumber(v) == resType then
            isInOnly = true
        end
    end
    if not isInOnly then
        LPlayerPrefs.GMSetLocalization(ref.parameter)
    end
    if parameterOnly and #parameterOnly == 1 then
        -- 可修改的资源只有1个且等于parameter时，不允许通过其他方式修改资源版本
        local first = parameterOnly[1]
        if checknumber(first) == ref.parameter then
            --- 限制资源修改
            LPlayerPrefs.LimitResType(true)
        end
    end
end

function LSdkCpX3:GetAfStatus()
    return gModelGM:GetAfStatus()
end

function LSdkCpX3:UpdateAfStatusABTest()
    local afStatus = self:GetAfStatus()
    local isAfStatusInit = true
    if isAfStatusInit then
        local ref = self:GetSdkChnResourcesRef()
        self:SetSdkChnResourcesRef(ref)
        local isOpenSex = gLGameLogin and gLGameLogin:IsOpenSex()
        if ref.attribution == 0 then
            if afStatus == "Organic" then
                LPlayerPrefs.GMSetLocalization(ref.nature)
            else
                if isOpenSex then
                    LPlayerPrefs.GMSetLocalization(ref.advertising)
                end
            end
        end
        if gModelPlayer then
            gModelPlayer:CheckNeedTranslateResType()
        end
        if afStatus then
            LogWarn("打印：afStatus = " .. afStatus .. ",屏蔽状态：" .. (isOpenSex and "开启" or "关闭"))
        end
        return true,isOpenSex
    end
    return true,true
end

